type ValueLength = 'short' | 'moderate' | 'long' | 'very-long';

const getTestValue = (valueLength: ValueLength): string => {
  switch (valueLength) {
    case 'short':
      return '100';
    case 'moderate':
      return MODERATE_LONG_VALUE;
    case 'long':
      return LONG_VALUE;
    case 'very-long':
      return VERY_LONG_VALUE;
    default:
      return '100';
  }
};

