type Sub = Set<() => void>;

const createPinAllHandler = (sub: Sub) => () => {
  sub.forEach((action) => action());
};

const usePinAllSetup = () => {
  const sub: Sub = new Set();
  const onClick = createPinAllHandler(sub);
  return { sub, onClick };
};

const chunkArray = <T,>(array: T[], size: number): T[][] => {
  const rows: T[][] = [];
  for (let i = 0; i < array.length; i += size) {
    rows.push(array.slice(i, i + size));
  }
  return rows;
};

const TogglePinned = (props: { sub: Sub }) => {
  const isPinned = useRef(false);
  useEffect(() => {
    const toggleFn = () => {
      isPinned.current = !isPinned.current;
    };
    props.sub.add(toggleFn);
    return () => {
      props.sub.delete(toggleFn);
    };
  }, [props.sub]);
  return null;
};

const Content = (
  props: PropsWithChildren<{
    sub: Sub;
    width?: string;
    minHeight?: string;
    getData: () => Data;
  }>,
) => (
  <OverlayProvider>
    <TooltipProvider>
      <TogglePinned sub={props.sub} />
      <div
        style={{
          width: props.width || '350px',
          height: '100%',
          maxWidth: '100%',
          maxHeight: '100%',
          resize: 'both',
          minHeight: props.minHeight || '200px',
          borderRight: '1px dashed #DDA0DD',
          overflow: 'hidden',
          position: 'relative',
        }}
      >
        <DummyInteractionsOverlay getData={props.getData}>
          {props.children}
        </DummyInteractionsOverlay>
      </div>
    </TooltipProvider>
  </OverlayProvider>
);

const TooltipGrid = (props: {
  sub: Sub;
  items: TestDataItem[];
  itemsPerRow?: number;
  width?: string;
  minHeight?: string;
}) => {
  const {
    sub,
    items,
    itemsPerRow = 3,
    width = '350px',
    minHeight = '200px',
  } = props;
  const rows = chunkArray(items, itemsPerRow);

  return (
    <>
      {rows.map((row, rowIndex) => (
        <Flex flexDirection="row" key={`row-${row[0].description}`}>
          {row.map((item, itemIndex) => {
            const key = rowIndex * itemsPerRow + itemIndex;
            return (
              <Flex flexDirection="column" key={key}>
                <h3>{item.description}</h3>
                <Content
                  sub={sub}
                  width={width}
                  minHeight={minHeight}
                  getData={item.data}
                >
                  {item.template}
                </Content>
              </Flex>
            );
          })}
        </Flex>
      ))}
    </>
  );
};

